        { name: "AccuraMeet", category: "Networking and Meeting App", platform: "Google Play", icon: "accurameet-icon.png", screenshot: "accurameet-screen.jpg", url: "https://play.google.com/store/apps/details?id=com.sagigroup.accurameet&pli=1", colors: "#2563eb,#7c3aed" },
        { name: "Runwey", category: "Fashion Discovery App", platform: "Google Play", icon: "runwey-icon.png", screenshot: "runwey-screen.png", url: "https://play.google.com/store/apps/details?id=com.joshua.runwey", colors: "#111827,#ec4899" },
        { name: "Pentagon Care Staffing", category: "Healthcare Staffing App", platform: "App Store", icon: "pentagon-care-icon.jpg", screenshot: "pentagon-care-screen.webp", url: "https://apps.apple.com/us/app/pentagon-care-staffing/id6738979360", colors: "#0f766e,#38bdf8" },
        { name: "WoContacts", category: "Service Providing App", platform: "Google Play", icon: "wocontacts-icon.png", screenshot: "wocontacts-screen.png", url: "https://play.google.com/store/apps/details?id=com.hkk4coding.wocontacts", colors: "#0ea5e9,#22c55e" },
        { name: "Tripadvisor", category: "Booking App", platform: "Google Play", icon: "tripadvisor-icon.png", screenshot: "tripadvisor-screen.jpg", url: "https://play.google.com/store/apps/details?id=com.tripadvisor.tripadvisor&hl=en", colors: "#00aa6c,#047857" },
        { name: "FitnessAI", category: "AI Powered Fitness App", platform: "Google Play", icon: "fitnessai-icon.png", screenshot: "fitnessai-screen.jpg", url: "https://play.google.com/store/apps/details?id=com.fitnessai.android&hl=en", colors: "#3b82f6,#8b5cf6" }
